extern char *str_dup(const char *s);
if (!s) return str_dup("\"\"");
size_t n = strlen(s);
char *out = (char *)malloc(n * 2 + 3);
if (!out) return NULL;
int oi = 0;
out[oi++] = '"';
for (size_t i = 0; i < n; i++) {
    char c = s[i];
    if (c == '"' || c == '\\') out[oi++] = '\\';
    out[oi++] = c;
}
out[oi++] = '"';
out[oi] = '\0';
return out;
